from dataclasses import dataclass

@dataclass
class CombinedModerationResult:
    allowed: bool
    block_reasons: list[str]
    openai_flagged: bool
    custom_flagged: list[str]

def combined_moderate(text: str) -> CombinedModerationResult:
    block_reasons: list[str] = []

    # Stage 1: OpenAI — fast, cheap, covers core harm categories
    flagged, reason = moderate_with_custom_thresholds(text)
    if flagged:
        block_reasons.append(f"openai:{reason}")

    # Stage 2: Custom Claude classifier — covers app-specific policy
    # Only run if stage 1 passed (save cost on already-blocked content)
    custom_result = None
    if not block_reasons:
        custom_result = custom_moderate(text)
        for cat in custom_result.categories_flagged:
            block_reasons.append(f"custom:{cat}")

    return CombinedModerationResult(
        allowed=len(block_reasons) == 0,
        block_reasons=block_reasons,
        openai_flagged=flagged,
        custom_flagged=custom_result.categories_flagged if custom_result else [],
    )

import hashlib, time
from typing import Optional

@dataclass
class CachedResult:
    result: CombinedModerationResult
    created_at: float
    ttl: float = 3600.0   # 1 hour default

    @property
    def expired(self) -> bool:
        return time.monotonic() - self.created_at > self.ttl

_mod_cache: dict[str, CachedResult] = {}

def _cache_key(text: str) -> str:
    # Normalise before hashing: lowercase, collapse whitespace
    normalised = " ".join(text.lower().split())[:1000]
    return hashlib.sha256(normalised.encode()).hexdigest()

def moderate_cached(text: str, ttl: float = 3600.0) -> CombinedModerationResult:
    key = _cache_key(text)
    entry = _mod_cache.get(key)
    if entry and not entry.expired:
        return entry.result
    result = combined_moderate(text)
    _mod_cache[key] = CachedResult(result=result, created_at=time.monotonic(), ttl=ttl)
    return result
